mapper.select:
SELECT * FROM (
    SELECT A.*, ROWNUM AS rn FROM (
        SELECT 
            p.place_id    AS "place_id",
            p.place_type  AS "place_type",
            p.name        AS "name",
            p.address     AS "address",
            p.view_count  AS "view_count",
            p.image_url   AS "image_url",
            p.created_at  AS "placeRegDate",
            r.category    AS "category"
        FROM PLACE p, RESTAURANT r
        WHERE p.place_id = r.restaurant_id

            AND r.areaCode = #{areaCode}

        /* [수정] DESC(내림차순)를 ASC(오름차순)로 변경 */
        ORDER BY p.created_at DESC 
    ) A
    WHERE ROWNUM <= #{end}
) WHERE rn >= #{start}

SELECT COUNT(*) 
FROM RESTAURANT 
WHERE Restaurant_ID = #{restaurant_id}

mapper.insert:

    SELECT SEQ_PLACE.NEXTVAL FROM DUAL

INSERT INTO PLACE (
    place_id, place_type, name, address, view_count, latitude, longitude, image_url, created_at
) VALUES (
    #{place_id}, 'REST', #{name}, #{address}, 0, #{latitude}, #{longitude}, #{image_url}, SYSTIMESTAMP
)

INSERT INTO RESTAURANT (
    restaurant_id, description, phone, category, status, restdate, areaCode
) VALUES (
    #{restaurant_id}, #{description, jdbcType=CLOB}, #{phone, jdbcType=VARCHAR}, #{category, jdbcType=VARCHAR}, 
    'OPEN',#{restdate, jdbcType=VARCHAR}, #{areaCode, jdbcType=VARCHAR} 
)
